import { useEffect, useMemo, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import LoadingPanel from "../../components/LoadingPanel";
import { fetchCategories, fetchProducts, selectAllCategories, selectAllProducts, selectLoadingByAction } from "../../store/catalogueSlice";

const toLabel = (value = "") => String(value).replace(/_/g, " ").replace(/\b\w/g, (char) => char.toUpperCase());

const AdminVariantsPage = () => {
  const dispatch = useDispatch(); const products = useSelector(selectAllProducts); const categories = useSelector(selectAllCategories); const loading = useSelector(selectLoadingByAction("fetchProducts")); const loadingCategories = useSelector(selectLoadingByAction("fetchCategories")); const [search, setSearch] = useState(""); const [categoryId, setCategoryId] = useState("");
  useEffect(() => { dispatch(fetchProducts({ pagination: { page: 1, pageSize: 5000 } })); dispatch(fetchCategories()); }, [dispatch]);
  const variantProducts = useMemo(() => products.filter((product) => { if (categoryId && String(product.category_id) !== String(categoryId)) return false; if (!search) return true; const haystack = [product.title, product.brand, product.category_name, ...(product.option_names || []), ...Object.values(product.option_values || {}).flat()].join(" ").toLowerCase(); return haystack.includes(search.toLowerCase()); }).sort((a, b) => Number(b.variant_count || 1) - Number(a.variant_count || 1)), [products, categoryId, search]);
  const totalVariants = useMemo(() => variantProducts.reduce((sum, product) => sum + Number(product.variant_count || 1), 0), [variantProducts]);
  const multiVariantProducts = useMemo(() => variantProducts.filter((product) => Number(product.variant_count || 1) > 1).length, [variantProducts]);
  if ((loading || loadingCategories) && !products.length) return <LoadingPanel title="Loading variants" message="Calculating variant matrices, option groups, and grouped product totals." variant="cards" />;
  return <div className="grid gap-6"><div className="flex flex-wrap items-start justify-between gap-4"><div><h1 className="m-0 text-3xl font-bold text-slate-900">Variants</h1><p className="mt-2 max-w-3xl text-sm leading-7 text-slate-500">Review which products have the richest variant setup and which option groups are being used across the catalogue.</p></div><Link to="/admin/products/new" className="btn-primary">Create product</Link></div><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-3"><div className="stat-card"><strong className="text-3xl font-bold text-slate-900">{products.length}</strong><div className="mt-2 text-sm text-slate-500">Products reviewed</div></div><div className="stat-card"><strong className="text-3xl font-bold text-slate-900">{multiVariantProducts}</strong><div className="mt-2 text-sm text-slate-500">Multi-variant products</div></div><div className="stat-card"><strong className="text-3xl font-bold text-slate-900">{totalVariants}</strong><div className="mt-2 text-sm text-slate-500">Variant rows</div></div></div><div className="surface-card grid gap-4 p-6"><div className="flex flex-wrap items-center justify-between gap-4"><div><h2 className="m-0 text-xl font-semibold text-slate-900">Variant catalogue</h2><p className="mt-2 text-sm text-slate-500">Search by product, category, or option values to find the product matrices you want to edit.</p></div><div className="flex flex-wrap gap-3"><input value={search} onChange={(event) => setSearch(event.target.value)} placeholder="Search variants" className="field-input max-w-xs" /><select value={categoryId} onChange={(event) => setCategoryId(event.target.value)} className="field-input max-w-xs"><option value="">All categories</option>{categories.map((category) => <option key={category.category_id || category.slug || category.name} value={category.category_id}>{category.name}</option>)}</select></div></div>{!variantProducts.length ? <div className="text-sm text-slate-500">No products matched your variant filters.</div> : <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">{variantProducts.map((product) => <article key={product.product_id} className="rounded-3xl border border-slate-200 bg-slate-50/70 p-5"><div className="grid gap-4"><div><h3 className="m-0 text-lg font-semibold text-slate-900">{product.title}</h3><p className="mt-2 text-sm text-slate-500">{product.category_name || product.category_id} · {product.brand || "Generic brand"}</p></div><div className="grid gap-2 text-sm text-slate-600"><div><strong>Variant rows:</strong> {product.variant_count || 1}</div><div><strong>Option groups:</strong> {(product.option_names || []).length || 0}</div></div><div className="flex flex-wrap gap-2">{(product.option_names || []).length ? product.option_names.map((name) => <span key={name} className="chip-blue">{toLabel(name)}</span>) : <span className="text-sm text-slate-500">No option groups</span>}</div><div className="grid gap-1.5 text-sm text-slate-600">{Object.entries(product.option_values || {}).slice(0, 3).map(([name, values]) => <div key={name}><strong>{toLabel(name)}:</strong> {(values || []).join(", ")}</div>)}</div><div className="flex flex-wrap gap-3"><Link to={`/admin/products/${product.product_id}`} className="btn-secondary">Edit matrix</Link><Link to={`/admin/products/${product.product_id}/view`} className="btn-outline">View</Link></div></div></article>)}</div>}</div></div>;
};

export default AdminVariantsPage;