import { CSV_FIELD_OPTIONS } from "../../utils/csvMapping";

const CsvMappingEditor = ({ headers, mapping, onChange }) => <section className="grid gap-4"><div><h2 className="m-0 text-2xl font-semibold text-slate-900">Column Mapping</h2><p className="mt-2 text-sm text-slate-500">Map vendor columns like <code>Product Name</code> or <code>MRP</code> to the catalogue fields used by the app.</p></div><div className="grid gap-3">{headers.map((header) => { const config = mapping[header] || { mode: "ignore", value: "" }; const selectedValue = config.mode === "field" ? config.value : config.mode === "custom" ? "__custom__" : "__ignore__"; return <div key={header} className="surface-card grid gap-3 p-4"><div><strong className="text-slate-900">{header}</strong><p className="mt-2 text-sm text-slate-500">{config.sample || "No sample values found"}</p></div><div className="grid gap-3 xl:grid-cols-[280px_minmax(0,1fr)]"><select value={selectedValue} onChange={(event) => { const next = event.target.value; if (next === "__ignore__") onChange(header, { ...config, mode: "ignore", value: "" }); else if (next === "__custom__") onChange(header, { ...config, mode: "custom", value: config.mode === "custom" ? config.value : header }); else onChange(header, { ...config, mode: "field", value: next }); }} className="field-input"><option value="__ignore__">Ignore this column</option>{CSV_FIELD_OPTIONS.map((option) => <option key={option.value} value={option.value}>{option.label}</option>)}<option value="__custom__">Keep as custom attribute</option></select>{config.mode === "custom" ? <input value={config.value || ""} onChange={(event) => onChange(header, { ...config, mode: "custom", value: event.target.value })} placeholder="Custom field name (e.g. battery, material)" className="field-input" /> : <div className="rounded-2xl border border-slate-200 bg-slate-50 px-4 py-3 text-sm text-slate-500">{config.mode === "field" ? `Mapped to ${config.value}` : "This column will be skipped during import."}</div>}</div></div>; })}</div></section>;

export default CsvMappingEditor;