import { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useNavigate, useParams } from "react-router-dom";
import ProductForm from "../../admin/products/ProductForm";
import LoadingPanel from "../../components/LoadingPanel";
import { createProduct, fetchCategories, fetchProductById, selectAllCategories, selectErrorByAction, selectLoadingByAction, selectProductDetailById, updateProduct, validateSku } from "../../store/catalogueSlice";

const emptyForm = { product_id: "", title: "", description: "", brand: "", price: "", image: "", inventory: "", category_id: "", status: "draft" };
const emptyInputs = { color: "", storage: "", screen_size: "" };
const attrSignature = (attributes = []) => (attributes || []).map((attribute) => `${attribute.attribute_name}:${attribute.attribute_value}`).sort().join("|");
const toLabel = (value = "") => String(value).replace(/_/g, " ").replace(/\b\w/g, (char) => char.toUpperCase());
const buildSku = (title, attributes = []) => [String(title || "product").trim().toUpperCase().replace(/[^A-Z0-9]+/g, "-").replace(/^-|-$/g, ""), ...(attributes || []).map((attribute) => String(attribute.attribute_value || "").trim().toUpperCase().replace(/[^A-Z0-9]+/g, "-")).filter(Boolean)].filter(Boolean).join("-");
const buildManualVariant = (form) => ({ sku: "", price: form.price || "", inventory: form.inventory || "", image: form.image || "", attributes: [] });
const buildAttributesFromCombo = (combo) => Object.entries(combo).filter(([, value]) => String(value).trim() !== "").map(([attribute_name, attribute_value]) => ({ attribute_name, attribute_label: toLabel(attribute_name), attribute_value }));
const hydrateVariant = (form, attributes, existing = {}) => ({ ...existing, sku: existing.sku || buildSku(form.title, attributes), price: existing.price || form.price || "", inventory: existing.inventory || form.inventory || "", image: existing.image || existing.primary_image || form.image || "", attributes });

const AdminProductEditorPage = () => {
  const { productId } = useParams();
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const categories = useSelector(selectAllCategories);
  const detail = useSelector((state) => selectProductDetailById(state, productId));
  const busy = useSelector(selectLoadingByAction(productId ? "updateProduct" : "createProduct"));
  const error = useSelector(selectErrorByAction(productId ? "updateProduct" : "createProduct"));
  const loadingDetail = useSelector(selectLoadingByAction("fetchProductById"));
  const skuValidation = useSelector((state) => state.catalogue.skuValidation);
  const [form, setForm] = useState(emptyForm); const [variantInputs, setVariantInputs] = useState(emptyInputs); const [variants, setVariants] = useState([]); const [formError, setFormError] = useState("");

  useEffect(() => { dispatch(fetchCategories()); if (productId) dispatch(fetchProductById({ data: { product_id: productId } })); }, [dispatch, productId]);
  useEffect(() => { if (!detail?.product) return; setForm({ product_id: detail.product.product_id || "", title: detail.product.title || "", description: detail.product.description || "", brand: detail.product.brand || "", price: detail.product.min_price || detail.product.price || "", image: detail.product.primary_image || detail.product.image || "", inventory: detail.product.inventory_total || detail.product.inventory || "", category_id: detail.product.category_id || "", status: detail.product.status || "draft" }); setVariantInputs({ color: detail.optionValues?.color?.join(", ") || "", storage: detail.optionValues?.storage?.join(", ") || "", screen_size: detail.optionValues?.screen_size?.join(", ") || "" }); setVariants((detail.variants || []).map((variant) => ({ ...variant, image: variant.primary_image || variant.image || "" }))); }, [detail]);

  const updateGeneratedVariants = (combinations, replaceExisting = false) => { setFormError(""); if (!combinations.length) return setFormError("Add at least one option value before generating variants."); setVariants((current) => { const existingBySignature = new Map(current.map((variant) => [attrSignature(variant.attributes), variant])); const generated = combinations.map((combo) => { const attributes = buildAttributesFromCombo(combo); return hydrateVariant(form, attributes, existingBySignature.get(attrSignature(attributes))); }); if (replaceExisting) return generated; const generatedSignatures = new Set(generated.map((variant) => attrSignature(variant.attributes))); return [...generated, ...current.filter((variant) => { const signature = attrSignature(variant.attributes); return !signature || !generatedSignatures.has(signature); })]; }); };
  const applyVariantDefaults = () => setVariants((current) => current.map((variant) => ({ ...variant, sku: variant.sku || buildSku(form.title, variant.attributes), price: variant.price || form.price || "", inventory: variant.inventory || form.inventory || "", image: variant.image || form.image || "" })));
  const generateMissingSkus = () => setVariants((current) => current.map((variant) => ({ ...variant, sku: variant.sku || buildSku(form.title, variant.attributes) })));

  const handleSubmit = async (event) => {
    event.preventDefault(); setFormError("");
    try {
      if (!form.title.trim()) throw new Error("Product title is required");
      const submittedVariants = variants.length ? variants : [buildManualVariant(form)];
      const seenSkus = new Set();
      for (const variant of submittedVariants) {
        const sku = String(variant.sku || "").trim();
        if (!sku) continue;
        const normalizedSku = sku.toUpperCase(); if (seenSkus.has(normalizedSku)) throw new Error(`Duplicate SKU found: ${sku}`); seenSkus.add(normalizedSku);
        await dispatch(validateSku({ data: { sku, variant_id: variant.variant_id || variant.id } })).unwrap();
      }
      const thunk = productId ? updateProduct : createProduct;
      await dispatch(thunk({ data: form, variants: submittedVariants })).unwrap();
      navigate("/admin/products", { state: { flashMessage: productId ? `Product “${form.title}” was updated successfully and synced from the sheet.` : `Product “${form.title}” was created successfully and added to the sheet.`, refreshOnLoad: true, refreshedAt: Date.now() } });
    } catch (submitError) { setFormError(submitError.message || String(submitError)); }
  };

  if (productId && loadingDetail && !detail?.product) return <LoadingPanel title="Loading product editor" message="Preparing grouped product data and variant rows for editing." variant="form" />;

  return <div className="grid gap-5"><header><h1 className="m-0 text-3xl font-bold text-slate-900">{productId ? "Edit Product" : "Create Product"}</h1><p className="mt-2 text-sm text-slate-500">Manage one product with multiple variant rows for your Google Sheet catalogue.</p></header>{(formError || error) && <div className="rounded-3xl border border-rose-200 bg-rose-50 px-5 py-4 text-sm text-rose-700">{formError || error}</div>}<ProductForm form={form} categories={categories} variantInputs={variantInputs} variants={variants} skuValidation={skuValidation} onChange={setForm} onVariantInputsChange={setVariantInputs} onVariantsChange={setVariants} onGenerateVariants={(combinations) => updateGeneratedVariants(combinations, false)} onReplaceVariants={(combinations) => updateGeneratedVariants(combinations, true)} onApplyVariantDefaults={applyVariantDefaults} onGenerateMissingSkus={generateMissingSkus} onClearVariantInputs={() => setVariantInputs(emptyInputs)} onSubmit={handleSubmit} submitLabel={productId ? "Save product" : "Create product"} busy={busy} /></div>;
};

export default AdminProductEditorPage;