import { useMemo, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import CsvMappingEditor from "./CsvMappingEditor";
import { selectImportValidation, selectLoadingByAction, uploadCSV, validateCsvImport } from "../../store/catalogueSlice";
import { analyzeCsvRows } from "../../utils/csvAnalysis";
import { buildImportSummary, buildMappedRows, getDefaultCsvMapping, summarizeMapping } from "../../utils/csvMapping";
import { parseCsvFile } from "../../utils/csvParser";

const ImportDropzone = () => {
  const dispatch = useDispatch(); const busy = useSelector(selectLoadingByAction("uploadCSV")); const validating = useSelector(selectLoadingByAction("validateCsvImport")); const validation = useSelector(selectImportValidation);
  const [rows, setRows] = useState([]); const [fileName, setFileName] = useState(""); const [mapping, setMapping] = useState({});
  const headers = useMemo(() => (rows[0] ? Object.keys(rows[0]) : []), [rows]);
  const mappedRows = useMemo(() => buildMappedRows(rows, mapping), [mapping, rows]);
  const localAnalysis = useMemo(() => analyzeCsvRows(mappedRows), [mappedRows]);
  const mappingSummary = useMemo(() => summarizeMapping(mapping), [mapping]);
  const analysis = validation || localAnalysis;

  const handleSelect = async (event) => { const file = event.target.files?.[0]; if (!file) return; const parsedRows = await parseCsvFile(file); setRows(parsedRows); setFileName(file.name); setMapping(getDefaultCsvMapping(parsedRows[0] ? Object.keys(parsedRows[0]) : [], parsedRows)); };
  const handleValidate = async () => { if (!mappedRows.length) return; await dispatch(validateCsvImport({ data: { rows: mappedRows, sourceFileName: fileName } })); };
  const handleImport = async () => { if (!mappedRows.length) return; await dispatch(uploadCSV({ data: { rows: mappedRows, sourceFileName: fileName, analysis: localAnalysis, summary: buildImportSummary(mappedRows, localAnalysis) } })); };

  return <div className="grid gap-6"><section className="surface-card grid gap-5 bg-gradient-to-br from-blue-50 via-white to-violet-50 p-6"><div className="flex flex-wrap items-start justify-between gap-4"><div><h2 className="m-0 text-2xl font-semibold text-slate-900">Upload and map your CSV</h2><p className="mt-2 max-w-3xl text-sm leading-7 text-slate-500">You can import one product, many products, or many variants in one file. If your supplier uses different headers, map them below before validating and importing.</p></div><label className="btn-primary cursor-pointer"><span>Select CSV</span><input type="file" accept=".csv" onChange={handleSelect} className="hidden" /></label></div><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4"><div className="stat-card"><strong className="text-3xl font-bold text-slate-900">{rows.length}</strong><span className="mt-2 block text-sm text-slate-500">Rows parsed</span></div><div className="stat-card"><strong className="text-3xl font-bold text-slate-900">{headers.length}</strong><span className="mt-2 block text-sm text-slate-500">Source columns</span></div><div className="stat-card"><strong className="text-3xl font-bold text-slate-900">{mappingSummary.mappedColumns}</strong><span className="mt-2 block text-sm text-slate-500">Mapped columns</span></div><div className="stat-card"><strong className="text-3xl font-bold text-slate-900">{mappingSummary.customColumns}</strong><span className="mt-2 block text-sm text-slate-500">Custom attributes</span></div></div><p className="m-0 text-sm text-slate-500">{fileName ? `${rows.length} rows parsed from ${fileName}` : "Choose a CSV to preview columns and begin mapping."}</p></section>{!!headers.length && <CsvMappingEditor headers={headers} mapping={mapping} onChange={(header, config) => setMapping((current) => ({ ...current, [header]: config }))} />}{!!mappedRows.length && <section className="surface-card grid gap-5 p-6"><div><h2 className="m-0 text-2xl font-semibold text-slate-900">Mapped preview</h2><p className="mt-2 text-sm leading-7 text-slate-500">This is the normalized data that will go into Google Sheet. Repeated <code>product_id</code> values will be grouped as variants of one product.</p></div><div className="grid gap-3 md:grid-cols-2 xl:grid-cols-4 text-sm text-slate-600"><div><strong>Product columns:</strong> {analysis.coreProductColumns.join(", ") || "None detected"}</div><div><strong>Variant columns:</strong> {analysis.coreVariantColumns.join(", ") || "None detected"}</div><div><strong>Dynamic attributes:</strong> {analysis.dynamicAttributes.join(", ") || "None detected"}</div><div><strong>Unique products:</strong> {analysis.uniqueProductCount || 0}</div></div>{!!analysis.rowErrors?.length && <div className="rounded-3xl border border-rose-200 bg-rose-50 px-5 py-4 text-rose-700"><strong>Validation issues</strong><ul className="mb-0 mt-3 list-disc space-y-1 pl-5">{analysis.rowErrors.slice(0, 10).map((issue, index) => <li key={`${issue.row}-${issue.field}-${index}`}>Row {issue.row}: {issue.message}</li>)}</ul></div>}<div className="table-shell"><div className="table-scroll"><table className="min-w-full border-collapse text-sm"><thead><tr>{Object.keys(mappedRows[0]).map((key) => <th key={key} className="th-cell">{key}</th>)}</tr></thead><tbody>{mappedRows.slice(0, 5).map((row, index) => <tr key={index}>{Object.keys(mappedRows[0]).map((key) => <td key={key} className="td-cell">{row[key]}</td>)}</tr>)}</tbody></table></div></div><div className="flex flex-wrap gap-3"><button type="button" onClick={handleValidate} disabled={validating || !mappedRows.length} className="btn-outline">{validating ? "Validating..." : "Validate mapped file"}</button><button type="button" onClick={handleImport} disabled={busy || !mappedRows.length || Boolean(analysis?.rowErrors?.length)} className="btn-primary">{busy ? "Importing..." : "Import to catalogue"}</button></div></section>}</div>;
};

export default ImportDropzone;